import{_ as d,o as e,c as a,a2 as r}from"./chunks/framework.y1bVONfd.js";const _=JSON.parse('{"title":"隐私脱敏","description":"自动 PII 检测和脱敏","frontmatter":{"title":"隐私脱敏","description":"自动 PII 检测和脱敏"},"headers":[],"relativePath":"zh/guide/desensitization.md","filePath":"zh/guide/desensitization.md"}'),o={name:"zh/guide/desensitization.md"};function i(n,t,s,l,h,c){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="隐私脱敏" tabindex="-1">隐私脱敏 <a class="header-anchor" href="#隐私脱敏" aria-label="Permalink to &quot;隐私脱敏&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>WebRouter 的脱敏引擎在请求到达上游 Provider 前，自动检测并替换个人身份信息（PII），响应中再还原原始数据。上游永远看不到敏感信息。</p><h2 id="内置规则" tabindex="-1">内置规则 <a class="header-anchor" href="#内置规则" aria-label="Permalink to &quot;内置规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>规则</th><th>分类</th><th>检测方式</th></tr></thead><tbody><tr><td>手机号</td><td><code>PHONE</code></td><td>正则匹配</td></tr><tr><td>姓名</td><td><code>NAME</code></td><td>中文姓名正则</td></tr><tr><td>地址</td><td><code>ADDRESS</code></td><td>地址关键词正则</td></tr><tr><td>身份证</td><td><code>IDCARD</code></td><td>模式匹配</td></tr><tr><td>邮箱</td><td><code>EMAIL</code></td><td>正则</td></tr></tbody></table><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><ol><li><strong>转发前</strong> — wr-proxy 扫描请求体中的 PII 模式</li><li><strong>替换</strong> — 匹配内容替换为占位符（<code>[PHONE_1]</code>、<code>[NAME_2]</code> 等）</li><li><strong>转发</strong> — 脱敏后的请求发送到上游</li><li><strong>响应</strong> — 上游正常返回</li><li><strong>还原</strong> — wr-proxy 将占位符恢复为原始值，返回给客户端</li></ol><h2 id="自定义规则" tabindex="-1">自定义规则 <a class="header-anchor" href="#自定义规则" aria-label="Permalink to &quot;自定义规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>规则标识</td></tr><tr><td>类型</td><td><code>regex</code></td></tr><tr><td>正则</td><td>匹配模式</td></tr><tr><td>分类</td><td>PHONE、NAME、ADDRESS、EMAIL、CUSTOM</td></tr><tr><td>级别</td><td><code>standard</code> 或 <code>strict</code></td></tr></tbody></table><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>脱敏按 Token 启用。创建或编辑 Token 时，打开<strong>脱敏开关</strong>即可为该 Token 开启请求脱敏。</p>',11)])])}const u=d(o,[["render",i]]);export{_ as __pageData,u as default};
